function isMostlyEnglish(text) {
  const raw = String(text ?? '').trim();
  if (!raw) {
    return true;
  }
  const cyr = (raw.match(/[\u0400-\u04FF]/g) ?? []).length;
  const lat = (raw.match(/[A-Za-z]/g) ?? []).length;
  if (cyr === 0 && lat > 0) {
    return true;
  }
  return lat > 10 && lat > cyr * 0.5;
}

export function translateKebabSegments(parts) {
  return parts.map((part) => KEBAB_SEGMENT_RU[part] ?? part).join(' ');
}

export function buildTitleFromWorkId(workId) {
  const parts = String(workId ?? '').split('-').filter(Boolean);
  if (parts.length === 0) {
    return '';
  }
  const head = parts[0];
  const tail = parts.slice(1);

  if (head === 'epic') {
    return `Эпик: ${translateKebabSegments(tail)}`;
  }
  if (head === 'bvc') {
    return `BVC: ${translateKebabSegments(tail)}`;
  }
  if (head === 'ux') {
    return `UX ${translateKebabSegments(tail)}`;
  }

  const ruPrefix = TITLE_PREFIX[head];
  if (ruPrefix) {
    const tailText = translateKebabSegments(tail);
    return `${ruPrefix}${ruPrefix.endsWith(':') ? ' ' : ' '}${tailText}`.replace(/\s{2,}/gu, ' ').trim();
  }

  return translateKebabSegments(parts);
}

function cyrillicScore(text) {
  return (String(text ?? '').match(/[\u0400-\u04FF]/g) ?? []).length;
}

function latinScore(text) {
  return (String(text ?? '').match(/[A-Za-z]/g) ?? []).length;
}

function pickBestTitle(candidates) {
  const list = candidates.map((value) => String(value ?? '').trim()).filter(Boolean);
  if (list.length === 0) {
    return '';
  }
  return list.sort((left, right) => scoreTitleCandidate(right) - scoreTitleCandidate(left))[0];
}

function scoreTitleCandidate(title) {
  const cyr = cyrillicScore(title);
  const lat = latinScore(title);
  let score = cyr * 3;
  if (cyr >= 12) score += 15;
  if (title.length > 95) score -= 25;
  if (title.length > 120) score -= 40;
  if (/^(?:реализовать|спроектировать|добавить|ADR:|написать|согласовать|документировать|мигрировать|вынести|подключить|закрытие|закрыть|аудит|канон|прототип|тесты|правило|шаг|определить|проанализировать|отложить|объединить|исправить|завершить|инвентаризация|раскатка|defer|опционально)/iu.test(title)) {
    score += 12;
  }
  if (lat > cyr && lat > 12) score -= lat;
  if (cyr < 6 && lat > 8) score -= 40;
  return score;
}

export { pickBestTitle, scoreTitleCandidate };

function protectTechnical(text, fn) {
  const tokens = [];
  const protectedText = String(text ?? '').replace(
    /(`[^`]+`|\b(?:npm run|IOHASC_[A-Z0-9_]+|WORKGRAPH_[A-Z0-9_]+|[a-z]+:[a-z-]+(?:\/[a-z-]+)*|\/?(?:src|docs|protocols|packages|tests|e2e|rules|domains|intent|work)\/[^\s,]+|\b[a-z][a-z0-9-]*\.(?:mjs|js|ts|step|json|jsonl|md|spec\.js))\b)/giu,
    (match) => {
      const key = `__TOK${tokens.length}__`;
      tokens.push(match);
      return key;
    },
  );
  let result = fn(protectedText);
  for (let index = 0; index < tokens.length; index += 1) {
    result = result.replace(`__TOK${index}__`, tokens[index]);
  }
  return result;
}

