export function rusifyProseLine(text) {
  if (!text || typeof text !== 'string') {
    return text;
  }
  const raw = text.trim();
  if (PROSE_LINE_EXACT_RU[raw]) {
    return PROSE_LINE_EXACT_RU[raw];
  }
  return rusifyLine(raw);
}

export function rusifyLine(text) {
  if (!text || typeof text !== 'string') {
    return text;
  }

  const result = protectTechnical(text, (input) => {
    let value = input;
    for (const [from, to] of PHRASE_REPLACEMENTS) {
      if (from.includes(' ') || from.length >= 8) {
        value = value.split(from).join(to);
      }
    }
    return value.replace(/\s{2,}/gu, ' ').trim();
  });

  return applyPostFixes(result);
}

