function applyPostFixes(text) {
  let value = String(text);
  for (const [from, to] of POST_FIXES) {
    value = value.split(from).join(to);
  }
  return value;
}

export function rusifyNextAction(nextAction, workId) {
  const raw = String(nextAction ?? '').trim();
  if (raw === '' || raw === '—') {
    return raw;
  }
  if (NEXT_ACTION_MAP[raw]) {
    return NEXT_ACTION_MAP[raw];
  }
  if (/^review and promote/i.test(raw)) {
    return 'просмотреть и перевести в ready';
  }
  if (/^[a-z0-9-]+$/u.test(raw) && raw.includes('-')) {
    return rusifyLine(raw.replace(/-/gu, ' '));
  }
  return rusifyLine(raw);
}

